// ========================================
// SCORE LEAD - Cálculo de Qualificação
// ========================================

const input = $input.first().json;

// 1. Extrair dados
const cnpj = (input.cnpj || '').replace(/\D/g, '');
const perfil = (input.perfil || '').toLowerCase();
const ufAtuacao = (input.uf_atuacao || '').toUpperCase();
const volumeStr = input.volume || '';
const cnae = input.cnae || '';
const fundacao = input.fundacao || '';

// 2. Extrair valor numérico do volume
const volumeMatch = volumeStr.match(/[\d.,]+/);
let volumeVal = 0;
if (volumeMatch) {
  volumeVal = parseFloat(volumeMatch[0].replace(/\./g, '').replace(',', '.'));
}

// 3. Verificar critérios de qualificação
const hasCnpjValido = cnpj.length === 14;

const ufsNorte = ['AC', 'AM', 'AP', 'PA', 'RO', 'RR', 'TO'];
const ufsNordeste = ['AL', 'BA', 'CE', 'MA', 'PB', 'PE', 'PI', 'RN', 'SE'];
const ufsAlvo = [...ufsNorte, ...ufsNordeste];
const isRegiaoAlvo = ufsAlvo.includes(ufAtuacao);

const volumeMinimo = 4000;
const hasVolumeMinimo = volumeVal >= volumeMinimo;

// 4. Determinar se está qualificado
const qualified = hasCnpjValido && isRegiaoAlvo && hasVolumeMinimo;

// 5. Se não qualificado, retornar imediatamente
if (!qualified) {
  let reason = 'Fora dos critérios: ';
  const motivos = [];
  if (!hasCnpjValido) motivos.push('CNPJ inválido');
  if (!isRegiaoAlvo) motivos.push('fora da região N/NE');
  if (!hasVolumeMinimo) motivos.push(`volume < R$${volumeMinimo}`);
  reason += motivos.join(', ');

  return {
    qualified: false,
    reason: reason,
    score: 0,
    class: 'desqualificado',
    priority: 'none'
  };
}

// 6. Calcular score (só para qualificados)
let score = 50; // Base

// +20 se volume >= 8000
if (volumeVal >= 8000) {
  score += 20;
} else if (volumeVal >= 5000) {
  score += 10;
}

// +10 se perfil é revenda (maior potencial)
if (perfil.includes('revenda') || perfil.includes('loja')) {
  score += 10;
}

// +10 se CNAE relevante (autopeças, iluminação, elétrica)
const cnaesRelevantes = ['4530', '4541', '4542', '4661', '4673', '4674', '4742', '4754'];
if (cnaesRelevantes.some(c => cnae.startsWith(c))) {
  score += 10;
}

// +5 se empresa tem mais de 5 anos
if (fundacao) {
  const anoFundacao = new Date(fundacao).getFullYear();
  const anosAtividade = new Date().getFullYear() - anoFundacao;
  if (anosAtividade >= 5) {
    score += 5;
  }
}

// Limitar score a 100
score = Math.min(score, 100);

// 7. Determinar classe e prioridade
let classe, priority;
if (score >= 80) {
  classe = 'quente';
  priority = 'urgent';
} else if (score >= 60) {
  classe = 'morno';
  priority = 'high';
} else {
  classe = 'frio';
  priority = 'medium';
}

return {
  qualified: true,
  reason: null,
  score: score,
  class: classe,
  priority: priority
};
